import software.amazon.awssdk.auth.credentials.AwsCredentialsProviderChain
import software.amazon.awssdk.auth.credentials.StaticCredentialsProvider
import software.amazon.awssdk.core.SdkClient
import software.amazon.awssdk.services.s3.S3Client
import com.typesafe.config.ConfigFactory
import java.util.concurrent.TimeUnit

object AwsService {
  private val config = ConfigFactory.load()
  private val accessKey = System.getenv("AWS_ACCESS_KEY_ID")
  private val secretKey = System.getenv("AWS_SECRET_ACCESS_KEY")

  def getAwsCredentials(): AwsCredentialsProviderChain = {
    if (accessKey != null && secretKey != null) {
      StaticCredentialsProvider.create(AwsCredentials.builder
        .accessKeyId(accessKey)
        .secretAccessKey(secretKey)
        .build())
    } else {
      AwsCredentialsProviderChain.defaultCredentials()
    }
  }

  def getS3Client(): S3Client = {
    val credentials = getAwsCredentials()
    S3Client.builder().credentialsProvider(credentials).build()
  }

  def listBuckets(): Unit = {
    val s3Client = getS3Client()
    val response = s3Client.listBuckets()
    println(response.buckets())
  }
}

object Main extends App {
  AwsService.listBuckets()
